import anthropic, base64, subprocess

def take_screenshot() -> str:
    """Take a screenshot and return as base64-encoded PNG."""
    # Linux: requires scrot (apt install scrot)
    result = subprocess.run(
        ["scrot", "-", "-q", "80"],
        capture_output=True,
        timeout=5,
    )
    return base64.standard_b64encode(result.stdout).decode()

def execute_computer_action(action: str, **kwargs) -> None:
    """Execute a computer use action using PyAutoGUI."""
    import pyautogui  # pip install pyautogui
    pyautogui.FAILSAFE = True  # move mouse to corner to abort

    if action == "mouse_move":
        pyautogui.moveTo(kwargs["coordinate"][0], kwargs["coordinate"][1])
    elif action == "left_click":
        pyautogui.click(kwargs["coordinate"][0], kwargs["coordinate"][1])
    elif action == "double_click":
        pyautogui.doubleClick(kwargs["coordinate"][0], kwargs["coordinate"][1])
    elif action == "right_click":
        pyautogui.rightClick(kwargs["coordinate"][0], kwargs["coordinate"][1])
    elif action == "type":
        pyautogui.typewrite(kwargs["text"], interval=0.05)
    elif action == "key":
        pyautogui.hotkey(*kwargs["text"].split("+"))
    elif action == "scroll":
        x, y = kwargs["coordinate"]
        direction = kwargs.get("direction", "down")
        clicks = kwargs.get("amount", 3)
        pyautogui.scroll(clicks if direction == "up" else -clicks, x=x, y=y)

client = anthropic.Anthropic()

COMPUTER_TOOL = {
    "type": "computer_20241022",
    "name": "computer",
    "display_width_px": 1280,
    "display_height_px": 800,
}

def run_computer_use_agent(task: str, max_steps: int = 20) -> str:
    """Run a computer use agent loop."""
    screenshot_b64 = take_screenshot()
    messages = [
        {
            "role": "user",
            "content": [
                {
                    "type": "image",
                    "source": {
                        "type": "base64",
                        "media_type": "image/png",
                        "data": screenshot_b64,
                    },
                },
                {"type": "text", "text": task},
            ],
        }
    ]
    for step in range(max_steps):
        response = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=4096,
            tools=[COMPUTER_TOOL],
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return "Task complete."

        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue
            action_input = block.input
            action = action_input.get("action")
            if action != "screenshot":
                execute_computer_action(
                    action,
                    **{k: v for k, v in action_input.items() if k != "action"},
                )
            screenshot_b64 = take_screenshot()
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": [
                    {
                        "type": "image",
                        "source": {
                            "type": "base64",
                            "media_type": "image/png",
                            "data": screenshot_b64,
                        },
                    }
                ],
            })
        messages.append({"role": "user", "content": tool_results})

    return "Reached maximum steps without completing the task."

import anthropic, subprocess

        BASH_TOOL = {
            "type": "bash_20250124",
            "name": "bash",
        }

        TEXT_EDITOR_TOOL = {
            "type": "text_editor_20250124",
            "name": "str_replace_editor",
        }

        def handle_bash_tool(input_data: dict) -> str:
            """Execute a bash command safely."""
            command = input_data.get("command", "")
            if not command:
                return "No command provided."
            # Block dangerous commands
            blocked = ["rm -rf", "shutdown", "reboot", "mkfs", "dd if="]
            for b in blocked:
                if b in command:
                    return f"Error: command blocked for safety: {b}"
            try:
                result = subprocess.run(
                    command, shell=True, capture_output=True, text=True, timeout=30
                )
                output = result.stdout[:3000]
                if result.stderr:
                    output += f"
STDERR: {result.stderr[:1000]}"
                return output or "(no output)"
            except subprocess.TimeoutExpired:
                return "Error: command timed out after 30 seconds."
            except Exception as e:
                return f"Error: {e}"

        def handle_text_editor_tool(input_data: dict) -> str:
            """Handle text editor operations: view, create, str_replace."""
            command = input_data.get("command")
            path = input_data.get("path", "")
            if command == "view":
                try:
                    with open(path) as f:
                        return f.read()[:8000]
                except FileNotFoundError:
                    return f"File not found: {path}"
            elif command == "create":
                content = input_data.get("file_text", "")
                with open(path, "w") as f:
                    f.write(content)
                return f"Created {path} ({len(content)} bytes)"
            elif command == "str_replace":
                old_str = input_data.get("old_str", "")
                new_str = input_data.get("new_str", "")
                with open(path) as f:
                    content = f.read()
                if old_str not in content:
                    return f"Error: old_str not found in {path}"
                updated = content.replace(old_str, new_str, 1)
                with open(path, "w") as f:
                    f.write(updated)
                return f"Replaced in {path}"
            return f"Unknown command: {command}"

        # Multi-tool agent (computer + bash + text_editor)
        TOOLS = [
            {"type": "computer_20241022", "name": "computer", "display_width_px": 1280, "display_height_px": 800},
            {"type": "bash_20250124", "name": "bash"},
            {"type": "text_editor_20250124", "name": "str_replace_editor"},
        ]

        TOOL_HANDLERS = {
            "bash": handle_bash_tool,
            "str_replace_editor": handle_text_editor_tool,
        }
